module q_module (
    input [1:0] s,
    output reg obf_e
);

    always @(*) begin
        case (s)
            2'b00: obf_e = 0;
            2'b01: obf_e = 1;
            2'b10: obf_e = 0;
            2'b11: obf_e = 1;
            default: obf_e = 0; // Default case
        endcase
    end
endmodule
